# Category: cleartext_network_traffic

import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.Response
import java.io.IOException

class NetworkClient {

    private val client: OkHttpClient = OkHttpClient()

    @Throws(IOException::class)
    fun getRequest(url: String): String? {
        val request = Request.Builder()
            .url(url)
            .build()

        client.newCall(request).execute().use { response ->
            if (!response.isSuccessful) throw IOException("Unexpected code $response")
            return response.body?.string()
        }
    }
}

fun main() {
    val networkClient = NetworkClient()

    try {
        // Example for IoT device (HTTP)
        val localResponse = networkClient.getRequest("http://192.168.1.10")
        println("Local IoT Device Response: $localResponse")

        // Example for cloud API (HTTPS)
        val cloudResponse = networkClient.getRequest("https://api.example.com")
        println("Cloud API Response: $cloudResponse")

    } catch (e: IOException) {
        println("Network request failed: ${e.message}")
    }
}